import{c as t,Q as a,j as o,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse(`{"title":"Claude Code's moat isn't the model. It's 9 pieces harness. I rebuilt them for DeepSeek. — @ShenHuang","description":"","frontmatter":{"title":"Claude Code's moat isn't the model. It's 9 pieces harness. I rebuilt them for DeepSeek. — @ShenHuang","author":"Shen Huang（@ShenHuang）","date":"2026-05-10T00:00:00.000Z","source":"https://x.com/ShenHuang/status/2053370791958569207","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-10-@ShenHuang-569207.md","filePath":"research/tweets/2026-05-10-@ShenHuang-569207.md","lastUpdated":1779894392000}`),n={name:"research/tweets/2026-05-10-@ShenHuang-569207.md"};function r(i,e,l,h,d,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="claude-code-s-moat-isn-t-the-model-it-s-9-pieces-harness-i-rebuilt-them-for-deepseek-—-shenhuang" tabindex="-1">Claude Code&#39;s moat isn&#39;t the model. It&#39;s 9 pieces harness. I rebuilt them for DeepSeek. — @ShenHuang <a class="header-anchor" href="#claude-code-s-moat-isn-t-the-model-it-s-9-pieces-harness-i-rebuilt-them-for-deepseek-—-shenhuang" aria-label="Permalink to &quot;Claude Code&#39;s moat isn&#39;t the model. It&#39;s 9 pieces harness. I rebuilt them for DeepSeek. — @ShenHuang&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/ShenHuang/status/2053370791958569207" target="_blank" rel="noreferrer">https://x.com/ShenHuang/status/2053370791958569207</a><strong>作者</strong>：Shen Huang（@ShenHuang） <strong>發布日期</strong>：2026-05-10 <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Twitter Article <strong>統計</strong>：140 likes · 20 retweets · 49 bookmarks · 23617 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>DeepSeek and Claude trade wins on benchmarks, but DeepSeek-via-raw-API feels broken next to Claude Code. The gap isn&#39;t the model — it&#39;s nine pieces of harness almost nobody ships. I built them and open-sourced the result.</p><h2 id="the-mismatch" tabindex="-1">The mismatch <a class="header-anchor" href="#the-mismatch" aria-label="Permalink to &quot;The mismatch&quot;">​</a></h2><p>DeepSeek V4 is roughly 1/50 the cost of Claude Opus 4.7 per million tokens.</p><p>Yet most engineers who try to swap Claude Code for raw DeepSeek give up inside a day. &quot;Forgets things, can&#39;t fix its own bugs, doesn&#39;t read my files.&quot;</p><p>The instinct is to blame the model. It&#39;s not the model.</p><p>It&#39;s that you&#39;re comparing a model in a jar to a model wearing a fully built-out harness — tools, permission gating, cache discipline, LSP feedback, MCP, sub-agents, compaction, a TUI you actually want to live in. <strong>The harness is 80% of the product. Claude Code ships it. The DeepSeek API does not.</strong> Nobody else is filling that gap end-to-end either.</p><p>I spent ten weeks filling it. Below is the actual list of pieces that could fill the gap between DS V4 and Claude Opus</p><h2 id="the-nine-missing-pieces-for-ds-v4" tabindex="-1">The nine missing pieces for DS V4 <a class="header-anchor" href="#the-nine-missing-pieces-for-ds-v4" aria-label="Permalink to &quot;The nine missing pieces for DS V4&quot;">​</a></h2><h2 id="_1-tool-loop-with-permission-gates" tabindex="-1">1. Tool loop with permission gates <a class="header-anchor" href="#_1-tool-loop-with-permission-gates" aria-label="Permalink to &quot;1. Tool loop with permission gates&quot;">​</a></h2><p>Fifty-ish tools (read / edit / write / bash / grep / glob / web_fetch / git ops / etc.), each with a JSON schema, a permission tier (auto / ask / deny-in-plan), and a sane error-reinjection format.</p><p>The error format matters more than people think — &quot;model wrote bad JSON, here&#39;s the parse error&quot; needs to come back in a way the model can self-correct without burning three turns.</p><h2 id="_2-cache-aware-prompt-assembly" tabindex="-1">2. Cache-aware prompt assembly <a class="header-anchor" href="#_2-cache-aware-prompt-assembly" aria-label="Permalink to &quot;2. Cache-aware prompt assembly&quot;">​</a></h2><p>DeepSeek&#39;s prefix cache cuts cached tokens to ~10% of list price. Claim that discount or your 1/50 cost advantage halves overnight.</p><p>Two non-obvious rules:</p><ul><li><p>System prompt and tool schemas at the very top, byte-stable across turns. Reorder one tool, cache miss, full rebill.</p></li><li><p>Conversation strictly append-only. No retroactive edits to old user messages, no in-place compaction of old assistant turns. If you have to compact, snapshot the old prefix into a synthetic message and start a new prefix from there.</p></li></ul><p>Most ad-hoc agent loops trash the cache the first time they format something differently between turns.</p><h2 id="_3-reasoning-content-replay" tabindex="-1">3. reasoning_content replay <a class="header-anchor" href="#_3-reasoning-content-replay" aria-label="Permalink to &quot;3. reasoning_content replay&quot;">​</a></h2><p>V4 thinking mode emits internal-monologue tokens that the user never sees. The non-obvious part: you have to feed them back into the model on the next turn or it loses the thread.</p><p>The Anthropic SDK won&#39;t help you here. You&#39;re lifting reasoning_content off the response and reattaching it as a structured assistant turn yourself.</p><p>Skip this and your agent feels lobotomized between messages — same model, dramatically worse continuity.</p><h2 id="_4-five-compaction-strategies" tabindex="-1">4. Five compaction strategies <a class="header-anchor" href="#_4-five-compaction-strategies" aria-label="Permalink to &quot;4. Five compaction strategies&quot;">​</a></h2><p>1M context isn&#39;t usable context. Per-tool-result micro-trim, threshold auto-summary, model-requested reactive compaction, durable session-memory extraction across runs, and a manual /snip.</p><p>You need all five because they fire at different time scales — the inline tool trim is per-turn, the auto-summary is per-N-tokens, the session-memory extraction is end-of-session, etc. One generic &quot;summarize when full&quot; doesn&#39;t cut it once you watch real sessions.</p><h2 id="_5-plan-agent-yolo-mode-separation" tabindex="-1">5. Plan / Agent / YOLO mode separation <a class="header-anchor" href="#_5-plan-agent-yolo-mode-separation" aria-label="Permalink to &quot;5. Plan / Agent / YOLO mode separation&quot;">​</a></h2><p>Three permission profiles, switchable mid-session.</p><p>Plan = read-only + draft, no writes;</p><p>Agent = writes with per-call confirmation;</p><p>YOLO = write-everything for unattended runs.</p><p>The mode is a function of allowed-tool-set × permission-default × confirmation-prompt-style. It&#39;s not just a UI toggle — it has to wrap the tool dispatcher and survive sub-agent spawning.</p><h2 id="_6-real-mcp-client" tabindex="-1">6. Real MCP client <a class="header-anchor" href="#_6-real-mcp-client" aria-label="Permalink to &quot;6. Real MCP client&quot;">​</a></h2><p>The ecosystem is the point — once you speak MCP, every Linear / GitHub / Postgres / Browser server is one config line away. Skip it and you&#39;re the only agent on the block writing one-off integrations.</p><h2 id="_7-lsp-feedback-loop" tabindex="-1">7. LSP feedback loop <a class="header-anchor" href="#_7-lsp-feedback-loop" aria-label="Permalink to &quot;7. LSP feedback loop&quot;">​</a></h2><p>Spawn the right language server (tsserver / rust-analyzer / pyright / gopls / clangd) and pipe diagnostics back into the model after every edit.</p><p>Model first-try fix rate goes from ~30% to ~80% once the LSP is in the loop.</p><p>Each server has its own init dance and its own quirks; this is grungy, ongoing work.</p><h2 id="_8-sub-agent-fan-out" tabindex="-1">8. Sub-agent fan-out <a class="header-anchor" href="#_8-sub-agent-fan-out" aria-label="Permalink to &quot;8. Sub-agent fan-out&quot;">​</a></h2><p>Main agent decomposes a long task into N independent sub-agents, each with fresh context, scoped tool budget, scoped permissions.</p><p>Results roll back into the parent. Cuts wall-clock for &quot;audit the codebase&quot; or &quot;refactor across 200 files&quot; by an order of magnitude.</p><p>The hard part is the contract: how do sub-agents stream progress, share artifacts, and fail gracefully without poisoning the parent?</p><h2 id="_9-tui-slash-commands-skill-loader" tabindex="-1">9. TUI + slash commands + skill loader <a class="header-anchor" href="#_9-tui-slash-commands-skill-loader" aria-label="Permalink to &quot;9. TUI + slash commands + skill loader&quot;">​</a></h2><p>Solid + opentui (or whatever — but please not Electron). Vim mode. Stable scroll buffer under streaming output. ~100 slash commands (/clear, /diff, /plan, /compact, /skill, ...). A skill loader that scans .openseek/skills, .claude/skills so the community&#39;s existing skill libraries Just Work.</p><p>This is &quot;just frontend&quot; except it&#39;s the entire surface the user touches. Get it wrong and the rest of the harness is invisible.</p><h2 id="so-what" tabindex="-1">So what? <a class="header-anchor" href="#so-what" aria-label="Permalink to &quot;So what?&quot;">​</a></h2><p>Build all nine, point it at DeepSeek V4, and the experience converges on Claude Code. At ~1/50 the cost.</p><p>That&#39;s a lot to build. So I built it.</p><p>openseek — Multi-provider out of the box: DeepSeek, any OpenAI-compat endpoint, Anthropic, Bedrock, Vertex, Azure. Same harness, swap the model.</p><p>Repo: <a href="https://github.com/LichAmnesia/openseek" target="_blank" rel="noreferrer">https://github.com/LichAmnesia/openseek</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 的護城河是 9 個 harness 元件（工具迴圈、cache 組裝、reasoning replay、compaction、模式分離、MCP、LSP、sub-agent、TUI），而非模型本身。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Harness 佔 Claude Code 體驗的 80%；裸 API 模型無法取代完整 harness</li><li>Cache-aware prompt assembly 需要系統 prompt + 工具 schema 位置固定、會話嚴格 append-only</li><li><code>reasoning_content</code> 必須手動 replay 回下一輪 assistant turn，否則模型上下文連續性大幅下降</li><li>LSP 反饋迴圈讓模型 first-try fix rate 從 30% 提升到 80%</li><li>Sub-agent fan-out 需要明確的進度串流、artifact 共享、故障隔離合約，不是只 spawn 就好</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>DeepSeek V4 成本約 Claude Opus 4.7 的 1/50（每百萬 token）</li><li>DeepSeek prefix cache 讓已快取 token 降至定價的 ~10%</li><li>LSP feedback loop：first-try fix rate 30% → 80%</li><li>工具數量：約 50+ 種（read/edit/write/bash/grep/glob/web_fetch/git ops 等）</li><li>openseek 開源專案：支援 DeepSeek、OpenAI-compat、Anthropic、Bedrock、Vertex、Azure</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>30% → 80% fix rate 和 1/50 成本優勢均為自我回報數據，缺乏控制組和可重現的實驗設計</li><li>作者聲稱 10 週獨自完成 9 個 harness 元件，規模與 cc-workspace 的 harness 設計高度重疊，但 openseek 的成熟度和維護持續性仍待觀察</li><li>「harness 是 80% 的產品」論點強化了現有 harness-design.md 的設計方向，但未討論不同任務類型下各元件的重要性差異</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>reasoning_content replay、LSP loop、5 種 compaction 策略分層直接對應 cc-workspace 待強化點</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>reasoning_content 必須手動 replay 和 LSP fix rate 量化主張是相對少見的工程細節</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>有具體數字但缺乏控制條件，均為自我回報；開源 repo 提供部分驗證基礎</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>9 個元件各有一段技術說明，cache byte-stability、compaction 分層等細節可直接指導實作</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>框架跨模型跨 provider，9 個元件是通用 agentic system 設計問題</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.05/10</strong></td><td>8×0.3+7×0.2+5×0.2+7×0.15+8×0.15 = 2.4+1.4+1.0+1.05+1.20</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：核心是「harness 9 元件通用原則」，補充 <code>.claude/refs/harness-design.md</code> 的元件清單與各元件技術要點。</p>',64)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
